SEVERITIES = ["critical", "high", "medium", "low"]
WEIGHT = {"critical": 40, "high": 10, "medium": 4, "low": 1}

def _risk(s):
    # open & deferred carry full weight; a patch is half-trusted until verified.
    r = 0.0
    for sev in SEVERITIES:
        w = WEIGHT[sev]
        r += w * s["open"][sev]
        r += w * s["deferred"][sev]
        r += 0.5 * w * s["patched"][sev]
    return round(r, 1)

def _totals(s):
    s["open_total"] = sum(s["open"].values())
    s["patched_total"] = sum(s["patched"].values())
    s["deferred_total"] = sum(s["deferred"].values())
    s["verified_total"] = sum(s["verified"].values())
    s["unscanned_total"] = sum(s["unscanned"].values())
    s["risk"] = _risk(s)
    return s

def _copy_pools(s):
    # deep-copy the per-severity pools so we never mutate the caller's dicts.
    for pool in ("unscanned", "open", "patched", "deferred", "verified"):
        s[pool] = dict(s[pool])
    return s

def transition(state, action):
    s = _copy_pools(dict(state))
    name = action.get("name") if isinstance(action, dict) else action
    s["day"] = s.get("day", 0) + 1
    s["last_action"] = name

    if name == "scan":
        # A scan surfaces every latent vulnerability into the open backlog.
        for sev in SEVERITIES:
            s["open"][sev] += s["unscanned"][sev]
            s["unscanned"][sev] = 0

    elif name == "patch":
        # Remediate one open vulnerability, highest severity first.
        for sev in SEVERITIES:                       # critical -> low
            if s["open"][sev] > 0:
                s["open"][sev] -= 1
                s["patched"][sev] += 1
                break

    elif name == "defer":
        # Postpone one open vulnerability, lowest severity first.
        for sev in reversed(SEVERITIES):             # low -> critical
            if s["open"][sev] > 0:
                s["open"][sev] -= 1
                s["deferred"][sev] += 1
                break

    elif name == "verify":
        # Confirm every applied patch as fully remediated.
        for sev in SEVERITIES:
            s["verified"][sev] += s["patched"][sev]
            s["patched"][sev] = 0

    # any other action is a no-op (the clock still advances)
    return _totals(s)

